def generate_draft(sender, config):
    context = sender.last_message()["content"]

    draft_prompt = f"""
    Based on intent: {context['intent']}
    Generate professional reply to: {context['original_email']}
    CC: {context['recipients']}
    Attachments: {context['attachments']}
    """

    response = draft_generator.generate_reply(messages=[{"role": "user", "content": draft_prompt}])
    return response

# Vex automatically filters unsafe attachments and PII before reply
draft_generator.register_reply(draft_generator, generate_draft)

approver_agent = AssistantAgent(
    name="Approver",
    system_message="Review final drafts. Flag issues. Request human approval if needed.",
    reply_filter=vex_client.filter(
        checks=["recipient_validation", "tone_appropriateness", "content_accuracy"]
    )
)

def final_review(sender, config):
    draft = sender.last_message()["content"]

    review = approver_agent.initiate_chat(
        sender,
        message=f"Final review: {draft}\nApprove for sending?",
        human_input_mode="ALWAYS"
    )

    if review.summary.approved:
        return send_email(draft)
    return "Draft rejected"

approver_agent.register_reply(approver_agent, final_review)

