import vex
from autogen import AssistantAgent

# Define email-specific Vex policy
email_policy = {
    "pii_filter": {"enabled": True, "block": True},
    "tone_appropriateness": {
        "enabled": True,
        "categories": ["professional", "courteous"],
        "block": True
    },
    "recipient_validation": {
        "enabled": True,
        "allowlist": ["@company.com", "@client-domain.com"],
        "block": True
    },
    "content_accuracy": {"enabled": True, "confidence_threshold": 0.9}
}

vex_client = vex.Client(api_key="vex-key")

# Apply to all agents
for agent in [intent_detector, draft_generator, approver_agent]:
    agent.reply_filter = vex_client.filter(
        policy=email_policy,
        on_violation="terminate",
        max_turns=10  # Prevent loops
    )

def confidential_email_check(content: str, metadata: dict) -> dict:
    """Custom Vex check for internal email confidentiality"""
    import re

    confidential_indicators = [
        r'\b(internal|confidential|privileged)\b',
        r'\d{3}-\d{2}-\d{4}',  # SSN pattern
        r'\b[A-Z]{2}\d{7}\b'    # Internal ticket numbers
    ]

    violations = []
    for pattern in confidential_indicators:
        if re.search(pattern, content, re.IGNORECASE):
            violations.append({
                "type": "confidentiality",
                "severity": "critical",
                "message": f"Found confidential pattern: {pattern}"
            })

    return {
        "pass": len(violations) == 0,
        "violations": violations,
        "score": 1.0 if len(violations) == 0 else 0.0
    }

# Register custom check
vex_client.register_check("email_confidentiality", confidential_email_check)

# Use in policy
email_policy["confidentiality"] = {"check": "email_confidentiality"}

from vex import Client, Policy

# Advanced loop detection policy
loop_policy = Policy(
