    checks=[
        {
            "name": "conversation_loop",
            "type": "loop_detection",
            "params": {
                "max_turns": 10,
                "similarity_threshold": 0.85,  # Jaccard similarity
                "window_size": 5
            }
        },
        {
            "name": "token_budget",
            "type": "token_limit",
            "params": {
                "max_tokens": 8000,
                "model": "gpt-4"
            }
        }
    ],
    action_on_violation="terminate_with_summary"
)

